/bin/zsh -lc "node - <<'NODE'
const assert = require('assert');
const { diffServices } = require('./src/deploy/reconciler');
const desired = [
  { name: 'api', image: 'api:v2', replicas: 2 },
  { name: 'worker', image: 'worker:v1', replicas: 1 },
];
const current = [
  { name: 'worker', image: 'worker:v1', replicas: 1 },
  { name: 'api', image: 'api:v1', replicas: 2 },
  { name: 'old', image: 'old:v1', replicas: 1 },
];
assert.deepStrictEqual(diffServices(desired, current), [
  { type: 'update', name: 'api', before: current[1], after: desired[0] },
  { type: 'delete', name: 'old' },
]);
assert.deepStrictEqual(diffServices([{ name: 'new', image: 'x', replicas: 1 }], []), [
  { type: 'create', name: 'new' },
]);
console.log('reconciler self-check passed');
NODE"
